code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Input, Select, Button, icon } from 'decantr/components';

code.example:
function FilterBar({ onSearch, onCategory, onStatus }) {
  const { div } = tags;

  return div({ class: css('_flex _row _gap3 _aic _w[100%] _py2') },
    Input({ placeholder: 'Search...', oninput: onSearch, class: css('_mw[300px] _flex1') }),
    Select({ placeholder: 'Category', onchange: onCategory, class: css('_w[160px]') },
      Select.Option({ value: 'all' }, 'All Categories'),
      Select.Option({ value: 'active' }, 'Active'),
      Select.Option({ value: 'archived' }, 'Archived')
    ),
    Select({ placeholder: 'Status', onchange: onStatus, class: css('_w[140px]') },
      Select.Option({ value: 'all' }, 'All'),
      Select.Option({ value: 'published' }, 'Published'),
      Select.Option({ value: 'draft' }, 'Draft')
    ),
    div({ class: css('_flex _gap2 _mlaut') },
      Button({ variant: 'outline', size: 'sm' }, icon('x'), 'Clear'),
      Button({ variant: 'primary', size: 'sm' }, icon('filter'), 'Apply')
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Input, Select, Button, Badge, icon } from 'decantr/components';

code.example:
function FilterBarCompact({ onSearch, onCategory, filters }) {
  const { div } = tags;

  return div({ class: css('_flex _row _gap2 _aic _w[100%] _py1') },
    Input({ placeholder: 'Search...', oninput: onSearch, class: css('_flex1') }),
    Button({ variant: 'outline', size: 'sm' }, icon('sliders-horizontal'), 'Filters'),
    ...(filters || []).map(f =>
      Badge({ variant: 'secondary', size: 'sm', class: css('_flex _aic _gap1') },
        f.label,
        Button({ variant: 'ghost', size: 'xs', onclick: f.onRemove }, icon('x', { size: '0.75rem' }))
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Input, Select, Button, Badge, icon } from 'decantr/components';

code.example:
function FilterBarAdvanced({ onSearch, onCategory, onStatus, filters, savedFilters }) {
  const { div, span } = tags;

  return div({ class: css('_flex _col _gap2 _w[100%] _py2') },
    div({ class: css('_flex _row _gap3 _aic') },
      Input({ placeholder: 'Search...', oninput: onSearch, class: css('_mw[300px] _flex1') }),
      Select({ placeholder: 'Category', onchange: onCategory, class: css('_w[160px]') },
        Select.Option({ value: 'all' }, 'All Categories'),
        Select.Option({ value: 'active' }, 'Active'),
        Select.Option({ value: 'archived' }, 'Archived')
      ),
      Select({ placeholder: 'Status', onchange: onStatus, class: css('_w[140px]') },
        Select.Option({ value: 'all' }, 'All'),
        Select.Option({ value: 'published' }, 'Published'),
        Select.Option({ value: 'draft' }, 'Draft')
      ),
      Button({ variant: 'outline', size: 'sm' }, icon('x'), 'Clear All')
    ),
    (filters && filters.length > 0) ? div({ class: css('_flex _row _gap2 _flexWrap') },
      span({ class: css('_textsm _fgmuted _aic _flex') }, 'Active:'),
      ...filters.map(f =>
        Badge({ variant: 'secondary', size: 'sm', class: css('_flex _aic _gap1') },
          f.label,
          Button({ variant: 'ghost', size: 'xs', onclick: f.onRemove }, icon('x', { size: '0.75rem' }))
        )
      )
    ) : null,
    (savedFilters && savedFilters.length > 0) ? div({ class: css('_flex _row _gap2') },
      span({ class: css('_textsm _fgmuted _aic _flex') }, 'Saved:'),
      ...savedFilters.map(sf =>
        Button({ variant: 'outline', size: 'xs', onclick: sf.onApply }, sf.name)
      )
    ) : null
  );
}

